  1→import { useState, useCallback } from 'react';
  2→import type { ChatMessage, ChatRequest } from '../types/chat';
  3→import type { LoanInput, LoanSummary, PrePayment, RateChange } from '../types/loan';
  4→
  5→interface UseChatProps {
  6→  loan: LoanInput;
  7→  summary: LoanSummary;
  8→  prePayments: PrePayment[];
  9→  rateChanges: RateChange[];
 10→}
 11→
 12→export const useChat = ({ loan, summary, prePayments, rateChanges }: UseChatProps) => {
 13→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 14→  const [isLoading, setIsLoading] = useState(false);
 15→
 16→  const sendMessage = useCallback(
 17→    async (content: string) => {
 18→      const userMessage: ChatMessage = {
 19→        id: crypto.randomUUID(),
 20→        role: 'user',
 21→        content,
 22→        timestamp: Date.now(),
 23→      };
 24→
 25→      setMessages((prev) => [...prev, userMessage]);
 26→      setIsLoading(true);
 27→
 28→      const assistantId = crypto.randomUUID();
 29→      setMessages((prev) => [
 30→        ...prev,
 31→        { id: assistantId, role: 'assistant', content: '', timestamp: Date.now() },
 32→      ]);
 33→
 34→      try {
 35→        const wp = summary.withPrePayments;
 36→        const totalPrePaymentAmount = prePayments.reduce((sum, pp) => sum + pp.amount, 0);
 37→
 38→        const recentMessages = [...messages, userMessage]
 39→          .slice(-10)
 40→          .map((m) => ({ role: m.role, content: m.content }));
 41→
 42→        const requestBody: ChatRequest = {
 43→          messages: recentMessages,
 44→          loanContext: {
 45→            principal: loan.principal,
 46→            annualRate: loan.annualRate,
 47→            emi: loan.emi,
 48→            startDate: loan.startDate,
 49→            totalInterest: wp.totalInterest,
 50→            totalAmountPaid: wp.totalAmountPaid,
 51→            closureDate: wp.closureDate,
 52→            totalMonths: wp.totalMonths,
 53→            interestSaved: summary.interestSaved,
 54→            monthsSaved: summary.monthsSaved,
 55→            prePaymentsCount: prePayments.length,
 56→            totalPrePaymentAmount,
 57→            rateChangesCount: rateChanges.length,
 58→          },
 59→        };
 60→
 61→        const response = await fetch('/api/chat', {
 62→          method: 'POST',
 63→          headers: { 'Content-Type': 'application/json' },
 64→          body: JSON.stringify(requestBody),
 65→        });
 66→
 67→        if (!response.ok) {
 68→          throw new Error('Failed to get response');
 69→        }
 70→
 71→        const reader = response.body?.getReader();
 72→        if (!reader) throw new Error('No response body');
 73→
 74→        const decoder = new TextDecoder();
 75→        let buffer = '';
 76→
 77→        while (true) {
 78→          const { done, value } = await reader.read();
 79→          if (done) break;
 80→
 81→          buffer += decoder.decode(value, { stream: true });
 82→          const lines = buffer.split('\n');
 83→          buffer = lines.pop() ?? '';
 84→
 85→          for (const line of lines) {
 86→            if (!line.startsWith('data: ')) continue;
 87→            const data = line.slice(6).trim();
 88→            if (data === '[DONE]') break;
 89→
 90→            try {
 91→              const parsed = JSON.parse(data);
 92→              if (parsed.content) {
 93→                setMessages((prev) =>
 94→                  prev.map((m) =>
 95→                    m.id === assistantId ? { ...m, content: m.content + parsed.content } : m,
 96→                  ),
 97→                );
 98→              }
 99→            } catch {
100→              // skip malformed chunks
101→            }
102→          }
103→        }
104→      } catch {
105→        setMessages((prev) =>
106→          prev.map((m) =>
107→            m.id === assistantId
108→              ? { ...m, content: 'Sorry, I encountered an error. Please try again.' }
109→              : m,
110→          ),
111→        );
112→      } finally {
113→        setIsLoading(false);
114→      }
115→    },
116→    [messages, loan, summary, prePayments, rateChanges],
117→  );
118→
119→  const clearMessages = useCallback(() => {
120→    setMessages([]);
121→  }, []);
122→
123→  return { messages, isLoading, sendMessage, clearMessages };
124→};
