 1→export interface ChatMessage {
 2→  id: string;
 3→  role: 'user' | 'assistant';
 4→  content: string;
 5→  timestamp: number;
 6→}
 7→
 8→export interface ChatRequest {
 9→  messages: { role: 'user' | 'assistant'; content: string }[];
10→  loanContext: {
11→    principal: number;
12→    annualRate: number;
13→    emi: number;
14→    startDate: string;
15→    totalInterest: number;
16→    totalAmountPaid: number;
17→    closureDate: string;
18→    totalMonths: number;
19→    interestSaved: number;
20→    monthsSaved: number;
21→    prePaymentsCount: number;
22→    totalPrePaymentAmount: number;
23→    rateChangesCount: number;
24→  };
25→}
