 12→export const LoanForm = ({ loan, onSubmit }: Props) => {
 13→  const [principal, setPrincipal] = useState('');
 14→  const [rate, setRate] = useState('');
 15→  const [emi, setEmi] = useState('');
 16→  const [emiDay, setEmiDay] = useState('5');
 17→  const [startDate, setStartDate] = useState('');
 18→  const [isCollapsed, setIsCollapsed] = useState(false);
 19→
 20→  useEffect(() => {
 21→    if (loan) {
 22→      setPrincipal(String(loan.principal));
 23→      setRate(String(loan.annualRate));
 24→      setEmi(String(loan.emi));
 25→      setEmiDay(String(loan.emiDebitDay));
 26→      setStartDate(loan.startDate);
 27→    }
 28→  }, [loan]);
 29→
 30→  const handleSubmit = (e: React.FormEvent) => {
 31→    e.preventDefault();
 32→    onSubmit({
 33→      id: loan?.id || crypto.randomUUID(),
 34→      principal: Number(principal),
 35→      annualRate: Number(rate),
 36→      emi: Number(emi),
 37→      emiDebitDay: Number(emiDay),
 38→      startDate,
 39→    });
 40→    setIsCollapsed(true);
 41→  };
 42→
 43→  const inputClass =
 44→    'w-full rounded-xl border border-slate-200 bg-slate-50/50 px-4 py-2.5 text-sm text-slate-900 placeholder:text-slate-400 transition-colors focus:border-blue-500 focus:bg-white focus:outline-none focus:ring-2 focus:ring-blue-500/20';
 45→  const labelClass = 'block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1.5';
 46→
 47→  return (
 48→    <div className="rounded-2xl border border-slate-200 bg-white shadow-sm overflow-hidden">
 49→      {/* Header — always visible, clickable to toggle */}
 50→      <button
 51→        type="button"
 52→        onClick={() => setIsCollapsed(!isCollapsed)}
 53→        className="cursor-pointer w-full flex items-center justify-between gap-3 p-4 sm:px-6 lg:px-8 sm:pt-6 lg:pt-8"
