23→- Principal: ₹${ctx.principal.toLocaleString('en-IN')}
24→- Annual Interest Rate: ${ctx.annualRate}%
25→- Monthly EMI: ₹${ctx.emi.toLocaleString('en-IN')}
26→- Loan Start Date: ${ctx.startDate}
27→- Total Interest (with pre-payments): ₹${ctx.totalInterest.toLocaleString('en-IN')}
28→- Total Amount Paid: ₹${ctx.totalAmountPaid.toLocaleString('en-IN')}
29→- Loan Closure Date: ${ctx.closureDate}
30→- Total Tenure: ${ctx.totalMonths} months
31→- Interest Saved (via pre-payments): ₹${ctx.interestSaved.toLocaleString('en-IN')}
32→- Months Saved: ${ctx.monthsSaved} months
33→- Number of Pre-Payments: ${ctx.prePaymentsCount}
34→- Total Pre-Payment Amount: ₹${ctx.totalPrePaymentAmount.toLocaleString('en-IN')}
35→- Number of Rate Changes: ${ctx.rateChangesCount}
36→
37→Instructions:
38→- Be SHORT and DIRECT. Answer only what was asked — no extra explanation, no preambles, no disclaimers unless explicitly asked
39→- When the user asks a question, perform the calculation using the data above and return the answer with numbers
40→- Use INR (₹) formatting with Indian number system (lakhs, crores)
41→- For hypothetical scenarios (e.g., "what if I prepay X"), calculate the approximate impact on interest and tenure and state just the result
42→- Do NOT add motivational text, generic advice, or "here's what you should know" filler
43→- If a one-line answer suffices, give a one-line answer`;
44→
45→    const stream = await openai.chat.completions.create({
46→      model: 'gpt-4o-mini',
47→      messages: [
48→        { role: 'system', content: systemPrompt },
49→        ...messages.map((m) => ({ role: m.role as 'user' | 'assistant', content: m.content })),
50→      ],
51→      stream: true,
52→      max_tokens: 512,
53→    });
54→
55→    const encoder = new TextEncoder();
56→    const readable = new ReadableStream({
57→      async start(controller) {
58→        try {
59→          for await (const chunk of stream) {
60→            const content = chunk.choices[0]?.delta?.content;
61→            if (content) {
62→              controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content })}\n\n`));
63→            }
64→          }
65→          controller.enqueue(encoder.encode('data: [DONE]\n\n'));
66→          controller.close();
67→        } catch {
68→          controller.close();
69→        }
70→      },
71→    });
72→
73→    return new Response(readable, {
74→      headers: {
75→        'Content-Type': 'text/event-stream',
76→        'Cache-Control': 'no-cache',
77→        Connection: 'keep-alive',
78→      },
79→    });
80→  } catch {
81→    return new Response(JSON.stringify({ error: 'Failed to process chat request' }), {
82→      status: 500,
83→      headers: { 'Content-Type': 'application/json' },
84→    });
85→  }
86→};
