import OpenAI from 'openai';
import type { ChatRequest } from '@/types/chat';

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

export const POST = async (request: Request) => {
  try {
    const body: ChatRequest = await request.json();
    const { messages, loanContext } = body;

    if (!messages || messages.length === 0) {
      return new Response(JSON.stringify({ error: 'Messages are required' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    const ctx = loanContext;
    const systemPrompt = `You are a helpful loan advisor assistant. The user has an active loan with the following details:

- Principal: ₹${ctx.principal.toLocaleString('en-IN')}
- Annual Interest Rate: ${ctx.annualRate}%
- Monthly EMI: ₹${ctx.emi.toLocaleString('en-IN')}
- Loan Start Date: ${ctx.startDate}
- Total Interest (with pre-payments): ₹${ctx.totalInterest.toLocaleString('en-IN')}
- Total Amount Paid: ₹${ctx.totalAmountPaid.toLocaleString('en-IN')}
- Loan Closure Date: ${ctx.closureDate}
- Total Tenure: ${ctx.totalMonths} months
- Interest Saved (via pre-payments): ₹${ctx.interestSaved.toLocaleString('en-IN')}
- Months Saved: ${ctx.monthsSaved} months
- Number of Pre-Payments: ${ctx.prePaymentsCount}
- Total Pre-Payment Amount: ₹${ctx.totalPrePaymentAmount.toLocaleString('en-IN')}
- Number of Rate Changes: ${ctx.rateChangesCount}

Instructions:
- Be SHORT and DIRECT. Answer only what was asked — no extra explanation, no preambles, no disclaimers unless explicitly asked
- When the user asks a question, perform the calculation using the data above and return the answer with numbers
- Use INR (₹) formatting with Indian number system (lakhs, crores)
- For hypothetical scenarios (e.g., "what if I prepay X"), calculate the approximate impact on interest and tenure and state just the result
- Do NOT add motivational text, generic advice, or "here's what you should know" filler
- If a one-line answer suffices, give a one-line answer`;

    const stream = await openai.chat.completions.create({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: systemPrompt },
        ...messages.map((m) => ({ role: m.role as 'user' | 'assistant', content: m.content })),
      ],
      stream: true,
      max_tokens: 512,
    });

    const encoder = new TextEncoder();
    const readable = new ReadableStream({
      async start(controller) {
        try {
          for await (const chunk of stream) {
            const content = chunk.choices[0]?.delta?.content;
            if (content) {
              controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content })}\n\n`));
            }
          }
          controller.enqueue(encoder.encode('data: [DONE]\n\n'));
          controller.close();
        } catch {
          controller.close();
        }
      },
    });

    return new Response(readable, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
      },
    });
  } catch {
    return new Response(JSON.stringify({ error: 'Failed to process chat request' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }
};

